def can_form_palindrome(s):
    n = len(s)
    for i in range(n // 2):
        x = s[i]
        y = s[n - 1 - i]

        # Calculate possible transformations
        x_options = {x}
        y_options = {y}

        if x > 'a':
            x_options.add(chr(ord(x) - 1))
        if x < 'z':
            x_options.add(chr(ord(x) + 1))

        if y > 'a':
            y_options.add(chr(ord(y) - 1))
        if y < 'z':
            y_options.add(chr(ord(y) + 1))

        # Check if there's a common character in the options
        if x_options.isdisjoint(y_options):
            return False

    return True

