def number_to_string_format(n):
    if n == 0:
        return ""

    result = []
    str_n = str(n)
    length = len(str_n)

    for i, digit in enumerate(str_n):
        if digit != '0':
            power_of_10 = length - i - 1
            if power_of_10 > 0:
                result.append(f"{digit}*10**{power_of_10}")
            else:
                result.append(f"{digit}")

    return '+'.join(result)

