def can_transform(string1, string2):
    if len(string1) != len(string2):
        return False

    map1 = {}
    map2 = {}

    for char1, char2 in zip(string1, string2):
        if char1 in map1:
            if map1[char1] != char2:
                return False
        else:
            map1[char1] = char2

        if char2 in map2:
            if map2[char2] != char1:
                return False
        else:
