def transform_string(s):
    def move_consonant(c):
        if c in 'bcdfghjklmnpqrstvwxyz':
            new_char = chr(((ord(c) - ord('a') + 9) % 26) + ord('a'))
            if new_char in 'code':
                return c
            return new_char
        return c

    def move_vowel(c):
        if c in 'aeiou':
            new_char = chr(((ord(c) - ord('a') - 5) % 26) + ord('a'))
            if new_char in 'code':
                return c
            return new_char
        return c

    def handle_exceptions(c):
        if c == 'c':
            return 'b'
        elif c == 'o':
            return 'n'
        elif c == 'd':
            return 'a'
        elif c == 'e':
            return 'a'
        return c

    result = []
    for char in s:
        if char in 'bcdfghjklmnpqrstvwxyz':
            char = move_consonant(char)
        elif char in 'aeiou':
            char = move_vowel(char)
        char = handle_exceptions(char)
        result.append(char)

    return ''.join(result)

