def replace_yellow_with_green(color):
    # Define the mapping for HTML color names
    yellow_to_green = {
        "gold": "ForestGreen",
        "khaki": "LimeGreen",
        "lemonchiffon": "PaleGreen",
        "lightgoldenrodyellow": "SpringGreen",
        "lightyellow": "MintCream",
        "palegoldenrod": "LightGreen",
        "yellow": "Lime"
    }

    # Check if the input is a color name
    if color.isalpha():
        # Convert to lowercase for case-insensitive comparison
        color_lower = color.lower()
        # Return the corresponding green color if it's a yellow shade
        if color_lower in yellow_to_green:
            return yellow_to_green[color_lower]
        else:
            return color  # Return the original color if not yellow

    # Check if the input is a hex color code
    if color.startswith("#") and len(color) == 7:
        # Extract the RGB components
        r = int(color[1:3], 16)
        g = int(color[3:5], 16)
        b = int(color[5:7], 16)

        # Check if the color is considered "yellow"
        if r > b and g > b:
            # Rearrange the values: largest to G, middle to B, smallest to R
            rgb = sorted([r, g, b])
            new_color = f"#{rgb[0]:02X}{rgb[2]:02X}{rgb[1]:02X}"
            # Maintain the original case of the input
            if color.islower():
                return new_color.lower()
            else:
                return new_color.upper()
        else:
            return color  # Return the original color if not yellow

    # If the input is neither a recognized color name nor a valid hex code, return it unchanged
    return color

