def calc_tip(p, r):
    # Step 1: Round the price at the tens place
    if p % 10 >= 5:
        rounded_price = (p // 10 + 1) * 10
    else:
        rounded_price = (p // 10) * 10

    # Step 2: Calculate the base tip by dropping the singles place digit
    base_tip = rounded_price // 10

    # Step 3: Apply the satisfaction rating
    if r == 1:
        tip = base_tip + 1
    elif r == 0:
        tip = base_tip - 1
    elif r == -1:
        tip = (base_tip // 2) - 1

    # Ensure the tip is non-negative
    return max(tip, 0)

