def maximize_product(arr):
    # Calculate the total product of all elements
    total_product = 1
    zero_count = 0
    for num in arr:
        if num != 0:
            total_product *= num
        else:
            zero_count += 1

    # If there are more than one zero, the product will be zero for any non-zero element removed
    if zero_count > 1:
        return 0

    max_product = float('-inf')
    element_to_remove = None

    for num in arr:
        if num == 0:
            # If there's exactly one zero, removing it will give the product of all non-zero elements
            if zero_count == 1:
                current_product = total_product
            else:
                current_product = 0
        else:
            # Calculate the product if this element is removed
            current_product = total_product // num

        # Update the maximum product and the element to remove
        if current_product > max_product:
            max_product = current_product
            element_to_remove = num
        elif current_product == max_product:
            # If the product is the same, choose the smallest element
            if element_to_remove is None or num < element_to_remove:
                element_to_remove = num

    return element_to_remove

