from collections import deque

def min_steps_to_num(num):
    if num == 1:
        return 0

    queue = deque([(1, 0)])  # (current_number, steps)
    visited = set([1])

    while queue:
        current, steps = queue.popleft()

        if current == num:
            return steps

        next_num1 = current + 1
        next_num2 = current * 2

        if next_num1 not in visited and next_num1 <= num:
            visited.add(next_num1)
            queue.append((next_num1, steps + 1))

        if next_num2 not in visited and next_num2 <= num:
            visited.add(next_num2)
            queue.append((next_num2, steps + 1))

