def solve(s):
    vowels = "aeiou"
    vowel_list = []
    consonant_list = []

    # Separate vowels and consonants
    for char in s:
        if char in vowels:
            vowel_list.append(char)
        else:
            consonant_list.append(char)

    # Count vowels and consonants
    num_vowels = len(vowel_list)
    num_consonants = len(consonant_list)

    # If the difference in count is more than 1, return "failed"
    if abs(num_vowels - num_consonants) > 1:
        return "failed"

    # Sort both lists to get lexicographically smallest result
    vowel_list.sort()
    consonant_list.sort()

    # Determine which list to start with
    if num_vowels > num_consonants:
        first_list, second_list = vowel_list, consonant_list
    elif num_consonants > num_vowels:
        first_list, second_list = consonant_list, vowel_list
    else:
        # If equal, start with vowels
        first_list, second_list = vowel_list, consonant_list

    # Alternate between the two lists
    result = []
    for i in range(len(s)):
        if i % 2 == 0:
            result.append(first_list.pop(0))
        else:
            result.append(second_list.pop(0))

    return ''.join(result)

