def almost_everywhere_zero(n, k):
    n_str = str(n)
    length = len(n_str)
    memo = {}

    def count(pos, non_zero_count, tight):
        if pos == length:
            return 1 if non_zero_count == k else 0

        if (pos, non_zero_count, tight) in memo:
            return memo[(pos, non_zero_count, tight)]

        limit = int(n_str[pos]) if tight else 9
        total_count = 0

        for digit in range(0, limit + 1):
            new_non_zero_count = non_zero_count + (1 if digit != 0 else 0)
            if new_non_zero_count > k:
                continue

            new_tight = tight and (digit == limit)
            total_count += count(pos + 1, new_non_zero_count, new_tight)

        memo[(pos, non_zero_count, tight)] = total_count
        return total_count

    return count(0, 0, True)

