def is_polydivisible(n, b):
    length = len(n)
    for i in range(1, length + 1):
        num = int(n[:i], b)
        if num % i != 0:
            return False
    return True

def get_polydivisible(n, b):
    count = 0
    num = 0
    while count <= n:
        num_str = convert_to_base(num, b)
        if is_polydivisible(num_str, b):
            if count == n:
                return num_str
            count += 1
        num += 1

def convert_to_base(num, base):
    if num == 0:
        return "0"
    digits = []
    while num:
        digits.append(CHARS[num % base])
        num //= base
    return ''.join(reversed(digits))

