def solve_expression(expression):
    import re

    # Split the expression into parts
    match = re.match(r"([-\d?]+)([+*-])([-\d?]+)=([-\d?]+)", expression)
    if not match:
        return -1

    left_operand, operator, right_operand, result = match.groups()

    # Find all digits present in the expression
    present_digits = set(expression) - set('+-*=') - set('?')

    # Check each digit from 0 to 9
    for digit in map(str, range(10)):
        if digit in present_digits:
            continue

        # Replace '?' with the current digit
        left = left_operand.replace('?', digit)
        right = right_operand.replace('?', digit)
        res = result.replace('?', digit)

        # Check for leading zeros
        if (len(left) > 1 and left[0] == '0') or (len(right) > 1 and right[0] == '0') or (len(res) > 1 and res[0] == '0'):
            continue

        # Evaluate the expression
        try:
            left_val = int(left)
            right_val = int(right)
            result_val = int(res)

            if operator == '+':
                if left_val + right_val == result_val:
                    return int(digit)
            elif operator == '-':
                if left_val - right_val == result_val:
                    return int(digit)
            elif operator == '*':
                if left_val * right_val == result_val:
                    return int(digit)
        except ValueError:
            continue

    return -1

