def count_ways(n, k, min_factor, memo):
    if k == 1:
        return 1 if n >= min_factor else 0

    if (n, k, min_factor) in memo:
        return memo[(n, k, min_factor)]

    ways = 0
    for i in range(min_factor, n + 1):
        if n % i == 0:
            ways += count_ways(n // i, k - 1, i, memo)

    memo[(n, k, min_factor)] = ways
    return ways

