def count_QAQ_subsequences(s):
    n = len(s)
    count_QAQ = 0

    # Iterate over each character in the string
    for i in range(n):
        if s[i] == 'Q':
            # For each 'Q', find 'A' and then another 'Q'
            for j in range(i + 1, n):
                if s[j] == 'A':
                    for k in range(j + 1, n):
                        if s[k] == 'Q':
                            count_QAQ += 1
    return count_QAQ

