def balance_boxes(k, boxes):
    total_sum = sum(sum(box) for box in boxes)
    if total_sum % k != 0:
        return "No"

    target_sum = total_sum // k
    box_sums = [sum(box) for box in boxes]
    moves = {}

    for i in range(k):
        for num in boxes[i]:
            current_sum = box_sums[i]
            needed_sum = target_sum - (current_sum - num)
            if needed_sum in moves:
                moves[needed_sum].append((i, num))
            else:
                moves[needed_sum] = [(i, num)]

    used = [False] * k
    result = [None] * k

    def dfs(box_index, start_index, path):
        if box_index == k:
            return True

        current_sum = box_sums[box_index]
        needed_sum = target_sum - current_sum

        if needed_sum in moves:
            for i, num in moves[needed_sum]:
                if not used[i]:
                    used[i] = True
                    path.append((num, i + 1))
                    if dfs(box_index + 1, i, path):
                        return True
                    path.pop()
                    used[i] = False

        return False

    path = []
    if dfs(0, 0, path):
        result = ["Yes"]
        for num, box in path:
            result.append(f"{num} {box}")
        return "\n".join(result)
    else:
        return "No"

