def max_apple_groups(n):
    groups = []
    used = [False] * (n + 1)

    for i in range(n, 1, -1):
        if not used[i]:
            for j in range(i * 2, n + 1, i):
                if not used[j]:
                    groups.append((i, j))
                    used[i] = True
                    used[j] = True
                    break

    return groups

