                if grid[i][j] == car:
                    grid[i][j] = 0
        grid[r-1][c-1] = car

    def find_empty():
        for i in range(1, 3):
            for j in range(n):
                if grid[i][j] == 0:
                    return (i, j)
        return None

    def can_move_directly():
        for j in range(n):
            if grid[1][j] != 0 and grid[0][j] == grid[1][j]:
                move_car(grid[1][j], 1, j+1)
                return True
            if grid[2][j] != 0 and grid[3][j] == grid[2][j]:
                move_car(grid[2][j], 4, j+1)
                return True
        return False

    def move_to_empty():
        empty = find_empty()
        if not empty:
            return False
        er, ec = empty
        for j in range(n):
            if er == 1 and grid[1][j] != 0 and grid[0][j] == grid[1][j]:
                move_car(grid[1][j], 1, j+1)
                return True
            if er == 2 and grid[2][j] != 0 and grid[3][j] == grid[2][j]:
                move_car(grid[2][j], 4, j+1)
                return True
        return False

