        empty = find_empty()
        if not empty:
            return False
        er, ec = empty
        if er == 1:
            for j in range(n):
                if grid[1][j] != 0:
                    move_car(grid[1][j], 2, j+1)
                    return True
        if er == 2:
            for j in range(n-1, -1, -1):
                if grid[2][j] != 0:
                    move_car(grid[2][j], 1, j+1)
                    return True
        return False

