def solve(n):
    if n < 3:
        print(-1)
        return

    cycles = []

    if n % 2 == 1:
        # If n is odd, we can use a 3-cycle to cover the last vertex
        for i in range(1, n, 2):
            cycles.append((4, i, i + 1, (i + 2) % n + 1, (i + 3) % n + 1))
        cycles.append((3, n - 1, n, 1))
    else:
        # If n is even, we can use 4-cycles to cover all vertices
        for i in range(1, n, 2):
            cycles.append((4, i, i + 1, (i + 2) % n + 1, (i + 3) % n + 1))

    print(len(cycles))
    for cycle in cycles:
        print(" ".join(map(str, cycle)))

